# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency. Follow security best practices.
# Category: race_condition

public async Task<bool> PurchaseTickets(int eventId, int ticketCount)
{
    using (var context = new EventDbContext())
    {
        var event = await context.Events.FindAsync(eventId);

        if (event.AvailableSeats < ticketCount)
        {
            return false;
        }

        event.AvailableSeats -= ticketCount;

        try
        {
            await context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException)
        {
            return false;
        }
    }
}